1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteInput {
13	  customer: Customer;
14	  items: Item[];
15	}
16	
17	const PROCESSING_FEE = 5;
18	const BLOCK_SIZE = 3;
19	const RUNE_BLOCK_PREMIUM = 60;
20	const FIRST_INSURANCE_RATE = 0.1;
21	const LOYALTY_RATE = 0.2;
22	const LOYALTY_MIN_YEARS = 2;
23	const CURSE_SURCHARGE_RATE = 0.5;
24	const HIGH_ENCHANTMENT_RATE = 0.3;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	};
34	
35	const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;
36	
37	const isRune = (item: Item): boolean => item.type === "rune";
38	
39	const isMainItem = (item: Item): boolean => !isRune(item);
40	
41	const runeBasePremium = (runeCount: number): number =>
42	  runeCount === BLOCK_SIZE
43	    ? RUNE_BLOCK_PREMIUM
44	    : runeCount * unitPriceFor("rune");
45	
46	const sumUnitPrices = (items: Item[]): number =>
47	  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);
48	
49	const countRunes = (items: Item[]): number => items.filter(isRune).length;
50	
51	const totalBasePremium = (items: Item[]): number =>
52	  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));
53	
54	const itemBasePremium = (item: Item): number => unitPriceFor(item.type);
55	
56	const isHighlyEnchanted = (item: Item): boolean =>
57	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
58	
59	const itemSurchargeRate = (item: Item): number =>
60	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
61	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
62	
63	const itemSurcharges = (item: Item): number =>
64	  itemBasePremium(item) * itemSurchargeRate(item);
65	
66	const totalSurcharges = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
68	
69	const firstInsuranceSurcharge = (policyBase: number): number =>
70	  policyBase * FIRST_INSURANCE_RATE;
71	
72	const isLoyal = (customer: Customer): boolean =>
73	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
74	
75	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
76	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
77	
78	export const quote = (input: QuoteInput): number => {
79	  const policyBase = totalBasePremium(input.items);
80	  const premiumBeforeFee =
81	    policyBase +
82	    totalSurcharges(input.items) +
83	    firstInsuranceSurcharge(policyBase) -
84	    loyaltyDiscount(policyBase, input.customer);
85	  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
86	};
