11	      quote({
12	        customer: { yearsWithMHPCO: 0 },
13	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
14	      })
15	    ).toBe(115);
16	  });
17	  it("quote: single amulet, 0 yrs first quote → premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
18	    expect(
19	      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "amulet" }] })
20	    ).toBe(71);
21	  });
