59	  it.todo("quote: 2 runes + 1 moonstone → base 75 G (no block, different types) → premium 80 G");
60	  it.todo("quote: 3 runes + 3 moonstones → base 120 G (two separate blocks) → premium 125 G");
61	
62	  // --- Quote: item-specific modifiers ---
63	  it("quote: cursed sword (ench 3), 0 yrs first quote → base 100 + 50 curse + 10 first insurance + 5 fee = 165 G", () => {
64	    expect(
