79	  it.todo("quote: sword with enchantment 4 → no high-enchantment surcharge → premium 105 G");
80	  it.todo("quote: cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 = 180) → premium 185 G");
81	
82	  // --- Quote: policy-wide modifiers ---
83	  it("quote: loyalty discount applies at exactly 2 years (-20% of policy base) → premium 95 G (100 + 10 first - 20 loyalty + 5 fee)", () => {
84	    expect(
85	      quote({
86	        customer: { yearsWithMHPCO: 2 },
87	        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
88	      })
89	    ).toBe(95);
