91	  it.todo("quote: first insurance surcharge (+10%) applies to a first contract");
92	  it.todo("quote: follow-up contract discount (-15%) applies to the second quote in a scenario");
93	
94	  // --- Quote: modifier scope on multi-item policies ---
95	  it.todo("quote: cursed sword (100) + plain amulet (60) → base 160; curse adds 50 (50% of sword) → 210 before further modifiers and fee");
