118	  it.todo("claim: sword + amulet → insurance sum 1600, cap 3200");
119	  it.todo("claim: two swords → insurance sum 2000, cap 4000; two damage entries each own deductible");
120	  it.todo("claim: cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
121	  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only, not insurance sum)");
122	
123	  // --- Claim: cap exhaustion across successive claims ---
124	  it.todo("claim: sword (cap 2000), first claim 1500 → payout 1400, remaining cap 600");
125	  it.todo("claim: sword (cap 2000), second claim 1500 → payout 600 (reduced to remaining cap), remaining cap 0");
126	
